/* DMA 环形缓冲区架构定义 */
#define DMA_RING_BUF_SIZE  512u
#define DMA_HALF_THRESHOLD (DMA_RING_BUF_SIZE / 2)

typedef struct {
    volatile uint16_t write_ptr;  /* DMA 硬件维护，CPU 只读 */
    uint16_t            read_ptr;  /* CPU 维护 */
    uint8_t             buffer[DMA_RING_BUF_SIZE];
    volatile uint32_t   half_flag; /* DMA Half Transfer 标志 */
    volatile uint32_t   complete_flag; /* DMA Transfer Complete 标志 */
} dma_ring_buf_t;

/* 接口：调用者只看到这三个函数 */
void dma_ring_init(dma_ring_buf_t *ring);
uint16_t dma_ring_available(const dma_ring_buf_t *ring);
uint8_t dma_ring_read(dma_ring_buf_t *ring);
const uint8_t* dma_ring_peek(const dma_ring_buf_t *ring, uint16_t *len);

/* 内部：从 NDTR 寄存器反推 write_ptr */
static inline uint16_t dma_get_write_ptr(DMA_Stream_TypeDef *stream) {
    return DMA_RING_BUF_SIZE - (uint16_t)__HAL_DMA_GET_COUNTER(stream);
}

/* USART1 + DMA2 Stream5 Channel 4 循环接收模板
 * STM32F407 @ 168MHz, APB2 = 84MHz, 115200-8N1
 * 缓冲区: 512 bytes, DMA CIRCULAR mode
 */
#include "stm32f4xx_hal.h"

extern UART_HandleTypeDef huart1;
extern DMA_HandleTypeDef hdma_usart1_rx;

static dma_ring_buf_t uart1_ring;

void Uart1_DmaRing_Init(void) {
    dma_ring_init(&uart1_ring);

    /* 启动 DMA 循环接收：
     * 外设=&huart1.Instance->DR(0x40011004)
     * 内存=uart1_ring.buffer[0]
     * 长度=512, 循环模式
     */
    HAL_UARTEx_ReceiveToIdle_DMA(
        &huart1,
        uart1_ring.buffer,
        DMA_RING_BUF_SIZE);
}

/* DMA 传输一半时调用：前半块缓冲区有新数据 */
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart,
                                 uint16_t Size) {
    if (huart->Instance == USART1) {
        uart1_ring.half_flag = 1;
        /* 此时 DMA 正在填充后半块，前半块可安全读取 */
    }
}

/* DMA 传输完成时调用：处理尾部数据 */
void HAL_UART_IRQHandler(UART_HandleTypeDef *huart) {
    if (huart->Instance == USART1) {
        uart1_ring.complete_flag = 1;
    }
}

uint16_t dma_ring_available(const dma_ring_buf_t *ring) {
    uint16_t w = ring->write_ptr;
    uint16_t r = ring->read_ptr;
    return (w - r + DMA_RING_BUF_SIZE) & (DMA_RING_BUF_SIZE - 1);
}

uint8_t dma_ring_read(dma_ring_buf_t *ring) {
    if (dma_ring_available(ring) == 0) return 0;
    uint8_t byte = ring->buffer[ring->read_ptr];
    ring->read_ptr = (ring->read_ptr + 1) & (DMA_RING_BUF_SIZE - 1);
    return byte;
}

/* 缓存一致性检查 + 编译期断言 */

/* 将缓冲区放在无缓存区域（STM32F7 D2 SRAM, 0x30000000）*/
__attribute__((section(".d2_sram_no_cache")))
static uint8_t dma_buffer[1024];

/* 编译期断言：缓冲区大小必须是 2 的幂 */
_Static_assert((DMA_RING_BUF_SIZE & (DMA_RING_BUF_SIZE - 1)) == 0,
               "DMA buffer size must be power of 2");

/* Cortex-M7 缓存刷新辅助函数 */
static void dma_cache_invalidate(const void *addr, size_t size) {
    uint32_t aligned_start = (uint32_t)addr & ~(32 - 1);
    uint32_t aligned_end   = ((uint32_t)addr + size + 31) & ~(32 - 1);
    SCB_InvalidateDCache_by_Addr((uint32_t *)aligned_start,
                                  aligned_end - aligned_start);
}

/* 在中断中：只做标志置位，不处理数据 */
void DMA2_Stream5_IRQHandler(void) {
    if (__HAL_DMA_GET_FLAG(&hdma_usart1_rx, DMA_FLAG_FEIF5)) {
        __HAL_DMA_CLEAR_FLAG(&hdma_usart1_rx, DMA_FLAG_FEIF5);
    }
    HAL_DMA_IRQHandler(&hdma_usart1_rx);
    /* 注意：不在这里调用 dma_ring_read()！*/
}

/* 主循环或 RTOS 任务中：安全读取 */
void app_process_uart(void) {
    uint16_t avail = dma_ring_available(&uart1_ring);
    if (avail > 0) {
        const uint8_t *data;
        uint16_t len = dma_ring_peek(&uart1_ring, &data, &len);
        process_protocol_frame(data, len);
        dma_ring_consume(&uart1_ring, len);
    }
}

/* ===== 重构前：轮询 UART 接收（坏味道：CPU 空转） ===== */
/* 主循环每 1ms 调用一次 */
void Uart1_Poll_Task(void) {
    uint8_t byte;
    while (HAL_UART_Receive(&huart1, &byte, 1, 10) == HAL_OK) {
        if (byte == FRAME_START) {
            frame_idx = 0;
            in_frame = 1;
        } else if (in_frame) {
            frame_buf[frame_idx++] = byte;
            if (frame_idx >= MAX_FRAME_LEN) {
                in_frame = 0;  /* 超时重置 */
            }
        }
    }
    /* 问题：如果 1ms 内没有数据，CPU 白白空转
     * 如果数据突发超过 1ms 到达，字节被丢弃 */
}

/* ===== 重构后：DMA 循环接收（零拷贝 + 事件驱动） ===== */

/* 环形缓冲区结构 */
typedef struct {
    volatile uint16_t write_ptr;
    uint16_t          read_ptr;
    uint8_t           buffer[512];
} dma_ring_buf_t;

static dma_ring_buf_t ring;
static volatile uint8_t dma_half_ready = 0;

void Uart1_Dma_Init(void) {
    HAL_UARTEx_ReceiveToIdle_DMA(
        &huart1, ring.buffer, sizeof(ring.buffer));
}

void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart,
                                 uint16_t Size) {
    if (huart->Instance == USART1)
        dma_half_ready = 1;
}

/* 主循环：只在有数据时处理 */
void Uart1_DMA_Task(void) {
    /* 检查 HalfTransfer 标志 */
    if (dma_half_ready) {
        dma_half_ready = 0;
        /* 处理 ring.buffer 中已填满的前半部分 */
        process_pending_data();
    }

    /* 常规可用数据处理 */
    uint16_t avail = (ring.write_ptr - ring.read_ptr + 512) & 511;
    if (avail > 0) {
        uint8_t byte = ring.buffer[ring.read_ptr];
        ring.read_ptr = (ring.read_ptr + 1) & 511;
        handle_byte(byte);
    }
    /* 优势：无数据时 CPU 可以做其他事
     * 突发数据不会丢失（DMA 持续搬运） */
}
